import React from 'react';

function GameIFrame ({ title, url, h, w }) {
  return (
    <div>
      <iframe
        src={url}
        title={title}
        width={h}
        height={w}
        allowFullScreen
      ></iframe>
    </div>
  );
};

export default GameIFrame;
